mapper.update:
UPDATE check_request
SET check_state = #{checkState}
WHERE id = #{id}

mapper.select:
SELECT cr.register_id AS registerId, 'CHECK' AS itemType, mt.tech_name AS itemName, cr.id AS itemId, mt.tech_price AS amount, cr.check_state AS orderState, d.dept_name AS deptName, r.visit_date AS visitDate, cr.creation_time AS createTime, NULL AS payTime FROM check_request cr LEFT JOIN register r ON cr.register_id = r.id LEFT JOIN department d ON r.deptment_id = d.id LEFT JOIN medical_technology mt ON cr.medical_technology_id = mt.id WHERE r.patient_id = #{patientId} AND mt.tech_price IS NOT NULL AND mt.tech_price > 0
AND cr.check_state = #{orderState}
ORDER BY cr.creation_time DESC LIMIT #{limit} OFFSET #{offset}
